export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    // 1) UPLOAD: POST /upload  (multipart/form-data)
    if (request.method === "POST" && url.pathname === "/upload") {
      const form = await request.formData();
      const file = form.get("file");
      if (!(file instanceof File)) {
        return Response.json({ error: "No file field" }, { status: 400 });
      }

      // Build a unique key so two uploads never collide
      const key = `uploads/${Date.now()}-${crypto.randomUUID()}-${file.name}`;

      // Store the raw bytes in R2 (reading them back out is free)
      await env.BUCKET.put(key, file.stream(), {
        httpMetadata: { contentType: file.type },
      });

      // Remember the details in D1 (bound params = no SQL injection)
      await env.DB.prepare(
        "INSERT INTO files (key, filename, content_type, size_bytes, uploaded_at) VALUES (?, ?, ?, ?, ?)"
      )
        .bind(key, file.name, file.type, file.size, new Date().toISOString())
        .run();

      return Response.json({
        key,
        filename: file.name,
        url: `${url.origin}/files/${encodeURIComponent(key)}`,
      });
    }

    // 2) SERVE: GET /files/<key>
    if (request.method === "GET" && url.pathname.startsWith("/files/")) {
      const key = decodeURIComponent(url.pathname.slice("/files/".length));
      const object = await env.BUCKET.get(key);
      if (object === null) {
        return new Response("Not found", { status: 404 });
      }

      // Copy the stored content-type etc. onto the response, then stream it
      const headers = new Headers();
      object.writeHttpMetadata(headers);
      headers.set("etag", object.httpEtag);
      return new Response(object.body, { headers });
    }

    return new Response("Not found", { status: 404 });
  },
};
